import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import {
  getElectionByConstituency,
  updateElection
} from "../../api/electionsApi";

function ElectionDashboard() {
  const { id } = useParams(); // constituency id
  const [election, setElection] = useState(null);
  const [form, setForm] = useState({});

  useEffect(() => {
    getElectionByConstituency(id).then(res => {
      if (res.data && Object.keys(res.data).length > 0) {
        setElection(res.data);
      }
    });
  }, [id]);

  const save = async () => {
    await updateElection(election.id, form);
    alert("Election updated successfully");
  };

  if (!election) return <p>No election created for this constituency</p>;

  return (
    <div style={{ padding: "20px" }}>
      <h2>Election Management</h2>

      <p>
        <b>Current Status:</b> {election.status}
      </p>

      <hr />

      <h3>Candidate Application Phase</h3>

      <label>Application Deadline</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, application_deadline: e.target.value })
        }
      />

      <hr />

      <h3>Voter Registration Phase</h3>

      <label>Voter Registration Deadline</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, voter_registration_deadline: e.target.value })
        }
      />

      <hr />

      <h3>Election Schedule</h3>

      <label>Election Start Time</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, start_time: e.target.value })
        }
      />

      <br /><br />

      <label>Election End Time</label>
      <br />
      <input
        type="datetime-local"
        onChange={e =>
          setForm({ ...form, end_time: e.target.value })
        }
      />

      <br /><br />

      <button onClick={save}>Save Election Details</button>
    </div>
  );
}

export default ElectionDashboard;
